// Synthetic contact list (no real data). Mix of valid, invalid syntax,
// role-based, disposable-domain, and duplicate rows on purpose.
const contacts = [
  { email: 'Maya.Reed@northwind.co', name: 'Maya Reed' },
  { email: 'maya.reed@northwind.co', name: 'Maya R.' },
  { email: 'sales@northwind.co', name: 'Sales Desk' },
  { email: 'omar@contoso.com', name: 'Omar Diaz' },
  { email: 'broken@@nope', name: 'Broken Row' },
  { email: 'test@mailinator.com', name: 'Throwaway' },
  { email: 'jules@fabrikam.dev', name: 'Jules Tan' },
  { email: 'guest@guerrillamail.com', name: 'Temp User' },
  { email: 'priya@umbrella.io', name: 'Priya N.' },
  { email: 'postmaster@umbrella.io', name: 'Postmaster' }
];
return contacts.map(function (json) { return { json: json }; });

const ROLE_PREFIXES = ['info','admin','sales','support','abuse','postmaster','noreply','no-reply','contact','hello','office','billing'];
const DISPOSABLE = ['mailinator.com','guerrillamail.com','10minutemail.com','tempmail.com','trashmail.com','yopmail.com'];
const seen = [];
const out = [];
for (const item of $input.all()) {
  const j = item.json;
  const email = String(j.email || '').trim().toLowerCase();
  const local = email.split('@')[0] || '';
  const domain = email.split('@')[1] || '';
  const syntaxOk = /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
  const roleBased = ROLE_PREFIXES.indexOf(local) !== -1;
  const disposable = DISPOSABLE.indexOf(domain) !== -1;
  const duplicate = seen.indexOf(email) !== -1;
  seen.push(email);
  const flags = [];
  if (!syntaxOk) flags.push('invalid_syntax');
  if (roleBased) flags.push('role_based');
  if (disposable) flags.push('disposable_domain');
  if (duplicate) flags.push('duplicate');
  let bucket = 'clean';
  if (!syntaxOk || disposable) bucket = 'suppress';
  else if (roleBased || duplicate) bucket = 'risky';
  out.push({ json: Object.assign({}, j, {
    email: email, domain: domain, syntaxOk: syntaxOk, roleBased: roleBased,
    disposable: disposable, duplicate: duplicate, flags: flags, bucket: bucket
  }) });
}
return out;

const items = $input.all();
const total = items.length;
let clean = 0, risky = 0, suppress = 0;
for (const it of items) {
  const b = it.json.bucket;
  if (b === 'clean') clean++;
  else if (b === 'risky') risky++;
  else if (b === 'suppress') suppress++;
}
const pct = function (n) { return total ? Math.round((n / total) * 100) : 0; };
return [{ json: {
  total: total, clean: clean, risky: risky, suppress: suppress,
  cleanPct: pct(clean), riskyPct: pct(risky), suppressPct: pct(suppress),
  mailablePct: pct(clean + risky)
} }];

// Synthetic sending-domain posture. In production these come from DNS TXT lookups.
// Demonstrates the SPF / DKIM / DMARC scoring used before any bulk send or migration.
const domain = 'send.example-brand.com';
const spf = { present: true, record: 'v=spf1 include:_spf.example.com ~all', softfail: true };
const dkim = { present: true, selector: 'default', keyBits: 1024 };
const dmarc = { present: true, policy: 'none', pct: 100, hasRua: true, subdomainPolicy: null };
const findings = [];
let score = 100;
if (!spf.present) { findings.push({ sev: 'critical', msg: 'SPF missing' }); score -= 30; }
else if (spf.softfail) { findings.push({ sev: 'low', msg: 'SPF uses ~all (softfail); -all is stricter' }); score -= 5; }
if (!dkim.present) { findings.push({ sev: 'critical', msg: 'DKIM missing' }); score -= 30; }
else if (dkim.keyBits < 2048) { findings.push({ sev: 'medium', msg: 'DKIM key ' + dkim.keyBits + '-bit; upgrade to 2048' }); score -= 15; }
if (!dmarc.present) { findings.push({ sev: 'critical', msg: 'DMARC missing (Gmail/Yahoo bulk rules require p=none minimum)' }); score -= 30; }
else {
  if (dmarc.policy === 'none') { findings.push({ sev: 'medium', msg: 'DMARC p=none; move to quarantine after report review' }); score -= 15; }
  if (!dmarc.subdomainPolicy) { findings.push({ sev: 'low', msg: 'No explicit sp= subdomain policy' }); score -= 5; }
}
const grade = score >= 90 ? 'A' : score >= 75 ? 'B' : score >= 60 ? 'C' : 'F';
return [{ json: { domain: domain, spf: spf, dkim: dkim, dmarc: dmarc, score: score, grade: grade, findings: findings } }];
